      def _describe(subj, depth=0, visited=None):
          if visited is None:
              visited = set()
          if depth > 2 or subj in visited:
              return subj
          visited.add(subj)

          sub_triples = subject_map.get(subj, [])
          phrases = []
          for t in sub_triples:
